<?php namespace App\Services\Sales; use App\Models\Sales\SalesOrder; use App\Models\Sales\ApprovedOrder; use Illuminate\Support\Str; class OrderService { public function create($data) { return SalesOrder::create([...$data, 'order_number' => 'SO-'.Str::ulid(), 'created_by' => auth()->id()]); } public function approve(SalesOrder $order, $modifiedItems) { if ($order->isImmutable()) throw new \Exception('Order immutable'); $approved = ApprovedOrder::create(['sales_order_id' => $order->id, 'approved_by' => auth()->id(), 'modified_items' => $modifiedItems]); $order->update(['status' => 'APPROVED', 'approved_order_id' => $approved->id]); return $approved; } }
